var e=[{id:`L2_1`,type:`dialog`,speaker:`ROSARIA_FALLEN_CA_NULL`,text:{KOREA:`필멸자들은 날 마왕이라며 두려워하고, 시종들은 주인님이라며 섬기지.`,JPN:`定命の者は妾を魔王と恐れ、僕は主と崇める。`,ENG:`Mortals fear me for my title of the Demon Lord, and servants serve me while calling me Mistress.`,TWN:`必滅者因懼怕我而稱我為魔王，僕人們因侍奉我而尊我為主人。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ROSARIA_FALLEN_CA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`ROSARIA_FALLEN_CA_NULL`,text:{KOREA:`잿더미의 여왕, 북의 폭군, 내가 불리던 이름은 아주 많지만… 너에게는 각별한 이름으로 불리고 싶구나. 하나 골라보겠느냐?`,JPN:`灰の女王、北の暴君、妾の呼び名は数多あるが……其方には特別な名で呼ばれたいのう。どうじゃ、決めてみぬか？`,ENG:`Queen of Ashes, Tyrant of the North... I have been called many things. However, with you... I'd like to be called by something unique. Would you like to choose one?`,TWN:`灰燼女王、北方暴君，我曾有過很多稱號。但你……我希望能從你口中聽到特別的名字，來挑一個吧？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ROSARIA_FALLEN_CA_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};